 72→    protected function getBookerName(string $param, Order $order, ExternalBooking $externalBooking): ?string
 73→    {
 74→        $result = ExternalBooking::DEFAULT_NAME;
 75→
 76→        if (!$externalBooking->isDefaultName($param)) {
 77→            $methodOrder = 'getAuthor'.ucfirst($param);
 78→            if (\is_callable([$externalBooking, $methodOrder])) {
 79→                $result = $externalBooking->$methodOrder();
 80→            }
 81→        }
 82→
 83→        // 1 - Get Booker name with contact payer or set Default Name
 84→        if ($externalBooking->isDefaultName($param)) {
 85→            $methodOrder = 'get'.ucfirst($param);
 86→            if (\is_callable([$order, $methodOrder])) {
 87→                $result = $order->$methodOrder() ?? ExternalBooking::DEFAULT_NAME;
 88→            }
 89→        }
 90→
 91→        // 2 - Get Booker Name with datacustom
 92→        if (ExternalBooking::DEFAULT_NAME === $result && $externalBooking->isDefaultName($param)) {
 93→            $result = $order->getDatumcustom($param) ?? ExternalBooking::DEFAULT_NAME;
 94→        }
 95→
 96→        // 3 - Get Booker Name with first participant
 97→        if (ExternalBooking::DEFAULT_NAME === $result && $externalBooking->isDefaultName($param)) {
 98→            $items = $order->getItemsByType(ProductType::$typesWithValidity);
 99→
100→            if ($items->count() > 0) {
101→                $firstTicket = $items->first();
102→
103→                $method = 'get'.ucfirst($param);
104→                if (\is_callable([$firstTicket, $method])) {
105→                    $result = $firstTicket->$method() ?? ExternalBooking::DEFAULT_NAME;
106→                }
107→            }
108→        }
109→
110→        return $result;
111→    }
112→
113→    protected function getBookerPhone(Order $order, ExternalBooking $externalBooking): ?string
114→    {
115→        $phone = $order->getPhone();
116→
117→        if (null === $externalBooking->getAuthorPhone() && null !== $order->getDatumcustom('mobile')) {
118→            $phone = $order->getDatumcustom('mobile');
119→        }
120→
121→        // Replace booker phone number with mobile if mobile was set
122→        if (null !== $order->getMobile()) {
123→            $phone = $order->getMobile();
124→        }
125→
126→        return $phone;
127→    }
